generated_oml:
instance MABI_MAX_0100_FirstAxisRobot : DTDFVocab:Component [
    base:desc "First rotary joint of the six‑axial MABI MAX 0100 industrial robot featuring a permanent‑magnet synchronous motor, dual‑gear transmission, and dual encoders."
]

// --- Physical Sensing Components --------------------------------------------------
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor on the permanent‑magnet synchronous motor measuring I_M."
    DTDFVocab:producedData CurrentDataStream
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Angular encoder mounted on the motor side providing r_M."
    DTDFVocab:producedData MotorPositionDataStream
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Angular encoder mounted on the gearbox side providing r_G."
    DTDFVocab:producedData GearboxPositionDataStream
]

// -----------------------------------------------------------------------------
// Instances of the physical data streams (DataTransmitted)
instance CurrentDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]
instance MotorPositionDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]
instance GearboxPositionDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

// Derived data streams (torque and angular velocity)
instance DerivedTorqueDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor, MotorPositionEncoder, GearboxPositionEncoder
]
instance DerivedAngularVelocityDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder, GearboxPositionEncoder
]

// -----------------------------------------------------------------------------
// Data instances corresponding to the transmitted streams
instance CurrentData : DTDFVocab:Data [
    base:desc "Instantaneous motor current I_M measured as a time‑stamped data trace."
    DTDFVocab:fromData CurrentDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]
instance MotorPositionData : DTDFVocab:Data [
    base:desc "Motor‑side angular position r_M as a time‑stamped data trace."
    DTDFVocab:fromData MotorPositionDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]
instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Gearbox‑side angular position r_G as a time‑stamped data trace."
    DTDFVocab:fromData GearboxPositionDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]
instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Derived torque τ computed from motor current and position signals."
    DTDFVocab:fromData DerivedTorqueDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]
instance DerivedAngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω computed from motor and gearbox position signals."
    DTDFVocab:fromData DerivedAngularVelocityDataStream
    DTDFVocab:inputTo MqttBrokerEnabler
]

// -----------------------------------------------------------------------------
// Enablers --------------------------------------------------------------------
instance MqttBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker used to stream sensor data (I_M, r_M, r_G, τ, ω) to the digital twin."
    DTDFVocab:enables RealTimeFrictionModelIdentificationService, MaintenanceSchedulingService
]

instance MultiPhysicsSimulationInsight : DTDFVocab:Insight [
    base:desc "Insight into the accuracy of multi‑physics simulation models."
]
instance RunMultiPhysicsSimulationAction : DTDFVocab:Action [
    base:desc "Runs the multi‑physics simulation for the joint."
    DTDFVocab:IsAutomatic true
]

instance MultiPhysicsSimulationService : DTDFVocab:Service [
    base:desc "Multi‑physics simulation of motor, gearbox, and friction models."
    DTDFVocab:provides MultiPhysicsSimulationInsight, RunMultiPhysicsSimulationAction
]

instance SimulinkExecutionEnvironmentEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink environment feeding simulation models of motor, gearbox and friction."
    DTDFVocab:enables MultiPhysicsSimulationService, ContinuousFrictionParameterAdaptationService, SimulationModelRefinementService
]

instance SysMLModelingToolEnabler : DTDFVocab:Enabler [
    base:desc "SysML modeling tool used to create the structural model of the first joint."
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing semantic metadata and traceability for the digital twin."
