]
instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Dahl white‑box friction model capturing adhesion and stiction effects."
    DTDFVocab:inputTo SimulinkExecutionEnvironmentEnabler
]
instance LuGreFrictionModel : DTDFVocab:Model [
